import{_ as a,c as e,G as t,e as r,E as o,b as l}from"./chunks/framework.BrC0DRXd.js";const i=JSON.parse('{"title":"模块总结 分子与细胞","description":"生物必修一 分子与细胞","frontmatter":{"title":"模块总结 分子与细胞","tags":["模块总结"],"categories":["生物"],"date":"2025-11-28T00:00:00.000Z","description":"生物必修一 分子与细胞","articleGPT":"人机。","references":[{"title":null,"url":null}],"top":false,"head":[["link",{"rel":"canonical","href":"https://blog.xernhe.com/posts/25112801"}]]},"headers":[],"relativePath":"posts/25112801.md","filePath":"posts/25112801.md","lastUpdated":1768007403000}'),n={class:"MathJax",jax:"SVG",style:{direction:"ltr",position:"relative"}},h={style:{overflow:"visible","min-height":"1px","min-width":"1px","vertical-align":"-0.05ex"},xmlns:"http://www.w3.org/2000/svg",width:"1.131ex",height:"1.557ex",role:"img",focusable:"false",viewBox:"0 -666 500 688","aria-hidden":"true"},s={class:"MathJax",jax:"SVG",style:{direction:"ltr",position:"relative"}},p={style:{overflow:"visible","min-height":"1px","min-width":"1px","vertical-align":"-0.05ex"},xmlns:"http://www.w3.org/2000/svg",width:"2.262ex",height:"1.557ex",role:"img",focusable:"false",viewBox:"0 -666 1000 688","aria-hidden":"true"};const d=a({name:"posts/25112801.md"},[["render",function(a,i,d,c,u,m){return l(),e("div",null,[i[7]||(i[7]=t('<h2 id="第-2-章-组成细胞的分子" tabindex="-1">第 2 章 组成细胞的分子 <a class="header-anchor" href="#第-2-章-组成细胞的分子" aria-label="Permalink to &quot;第 2 章  组成细胞的分子&quot;">​</a></h2><h3 id="细胞中的无机物" tabindex="-1">细胞中的无机物 <a class="header-anchor" href="#细胞中的无机物" aria-label="Permalink to &quot;细胞中的无机物&quot;">​</a></h3><h4 id="水" tabindex="-1">水 <a class="header-anchor" href="#水" aria-label="Permalink to &quot;水&quot;">​</a></h4><p>自由水：细胞内良好的溶剂；为细胞提供液体环境；参与生化反应；运送营养物质和代谢废物。</p><p>结合水：组成细胞结构。</p><p>自由水与结合水比值越大，细胞代谢越旺盛，抗逆性越弱。</p><h4 id="无机盐" tabindex="-1">无机盐 <a class="header-anchor" href="#无机盐" aria-label="Permalink to &quot;无机盐&quot;">​</a></h4><p>作用：组成复杂的化合物；维持细胞和生物体的生命活动；维持细胞酸碱平衡；维持渗透压。</p><h3 id="细胞中的糖类和脂质" tabindex="-1">细胞中的糖类和脂质 <a class="header-anchor" href="#细胞中的糖类和脂质" aria-label="Permalink to &quot;细胞中的糖类和脂质&quot;">​</a></h3><h4 id="糖类" tabindex="-1">糖类 <a class="header-anchor" href="#糖类" aria-label="Permalink to &quot;糖类&quot;">​</a></h4><p>单糖：葡萄糖（主要能源物质）、果糖（提供能量）、半乳糖（提供能量）、核糖（RNA，ATP），脱氧核糖（DNA）。</p><p>二糖：麦芽糖（葡萄糖+葡萄糖）、蔗糖（葡萄糖+果糖）、乳糖（葡萄糖+半乳糖）。</p><p>多糖：淀粉（植物细胞中的储能物质）、糖原（动物细胞中的储能物质）、纤维素（植物细胞壁组成成分）、几丁质（昆虫外骨骼）。</p><p>淀粉在叶绿体中合成，糖原主要在肝脏和肌肉中合成。</p><h4 id="脂质" tabindex="-1">脂质 <a class="header-anchor" href="#脂质" aria-label="Permalink to &quot;脂质&quot;">​</a></h4><p>胆固醇：动物细胞膜的重要组成成分，同时参与血液中脂质的运输。</p><p>维生素 D：促进人和动物肠道对钙和磷的吸收。</p><p>脂质主要在光面内质网中合成。</p><p>与糖类相比，脂肪中氧的含量较低，氢的含量较高。所以等质量的糖和脂肪氧化分解时，脂肪释放的能量多，需要的氧气多。</p><p>在糖类供应充足时，可以大量转化为脂肪。在糖类代谢发生障碍时，脂肪才会分解供能，而且不能大量转化为糖类。</p><h3 id="蛋白质是生命活动的主要承担者" tabindex="-1">蛋白质是生命活动的主要承担者 <a class="header-anchor" href="#蛋白质是生命活动的主要承担者" aria-label="Permalink to &quot;蛋白质是生命活动的主要承担者&quot;">​</a></h3><p><strong>蛋白质是生命活动的主要承担者</strong>。</p><h4 id="蛋白质的功能" tabindex="-1">蛋白质的功能 <a class="header-anchor" href="#蛋白质的功能" aria-label="Permalink to &quot;蛋白质的功能&quot;">​</a></h4><p>分为结构蛋白和功能蛋白。结构蛋白，是构成细胞和生物体结构的重要物质；功能蛋白，能够催化、运输、调节、免疫。</p><p>蛋白质<strong>参与组成细胞结构、催化、运输、信息传递、防御等重要功能</strong>。</p><p>有些蛋白质同时具有多个功能，如钠钾泵就同时具有运输和催化的功能。</p><h4 id="氨基酸" tabindex="-1">氨基酸 <a class="header-anchor" href="#氨基酸" aria-label="Permalink to &quot;氨基酸&quot;">​</a></h4>',27)),r("p",null,[i[4]||(i[4]=o("分为 ")),r("mjx-container",n,[(l(),e("svg",h,i[0]||(i[0]=[r("g",{stroke:"currentColor",fill:"currentColor","stroke-width":"0",transform:"scale(1,-1)"},[r("g",{"data-mml-node":"math"},[r("g",{"data-mml-node":"mn"},[r("path",{"data-c":"38",d:"M70 417T70 494T124 618T248 666Q319 666 374 624T429 515Q429 485 418 459T392 417T361 389T335 371T324 363L338 354Q352 344 366 334T382 323Q457 264 457 174Q457 95 399 37T249 -22Q159 -22 101 29T43 155Q43 263 172 335L154 348Q133 361 127 368Q70 417 70 494ZM286 386L292 390Q298 394 301 396T311 403T323 413T334 425T345 438T355 454T364 471T369 491T371 513Q371 556 342 586T275 624Q268 625 242 625Q201 625 165 599T128 534Q128 511 141 492T167 463T217 431Q224 426 228 424L286 386ZM250 21Q308 21 350 55T392 137Q392 154 387 169T375 194T353 216T330 234T301 253T274 270Q260 279 244 289T218 306L210 311Q204 311 181 294T133 239T107 157Q107 98 150 60T250 21Z",style:{"stroke-width":"3"}})])])],-1)]))),i[1]||(i[1]=r("mjx-assistive-mml",{unselectable:"on",display:"inline",style:{top:"0px",left:"0px",clip:"rect(1px, 1px, 1px, 1px)","-webkit-touch-callout":"none","-webkit-user-select":"none","-khtml-user-select":"none","-moz-user-select":"none","-ms-user-select":"none","user-select":"none",position:"absolute",padding:"1px 0px 0px 0px",border:"0px",display:"block",width:"auto",overflow:"hidden"}},[r("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[r("mn",null,"8")])],-1))]),i[5]||(i[5]=o(" 种必需氨基酸和 ")),r("mjx-container",s,[(l(),e("svg",p,i[2]||(i[2]=[t('<g stroke="currentColor" fill="currentColor" stroke-width="0" transform="scale(1,-1)"><g data-mml-node="math"><g data-mml-node="mn"><path data-c="31" d="M213 578L200 573Q186 568 160 563T102 556H83V602H102Q149 604 189 617T245 641T273 663Q275 666 285 666Q294 666 302 660V361L303 61Q310 54 315 52T339 48T401 46H427V0H416Q395 3 257 3Q121 3 100 0H88V46H114Q136 46 152 46T177 47T193 50T201 52T207 57T213 61V578Z" style="stroke-width:3;"></path><path data-c="33" d="M127 463Q100 463 85 480T69 524Q69 579 117 622T233 665Q268 665 277 664Q351 652 390 611T430 522Q430 470 396 421T302 350L299 348Q299 347 308 345T337 336T375 315Q457 262 457 175Q457 96 395 37T238 -22Q158 -22 100 21T42 130Q42 158 60 175T105 193Q133 193 151 175T169 130Q169 119 166 110T159 94T148 82T136 74T126 70T118 67L114 66Q165 21 238 21Q293 21 321 74Q338 107 338 175V195Q338 290 274 322Q259 328 213 329L171 330L168 332Q166 335 166 348Q166 366 174 366Q202 366 232 371Q266 376 294 413T322 525V533Q322 590 287 612Q265 626 240 626Q208 626 181 615T143 592T132 580H135Q138 579 143 578T153 573T165 566T175 555T183 540T186 520Q186 498 172 481T127 463Z" transform="translate(500,0)" style="stroke-width:3;"></path></g></g></g>',1)]))),i[3]||(i[3]=r("mjx-assistive-mml",{unselectable:"on",display:"inline",style:{top:"0px",left:"0px",clip:"rect(1px, 1px, 1px, 1px)","-webkit-touch-callout":"none","-webkit-user-select":"none","-khtml-user-select":"none","-moz-user-select":"none","-ms-user-select":"none","user-select":"none",position:"absolute",padding:"1px 0px 0px 0px",border:"0px",display:"block",width:"auto",overflow:"hidden"}},[r("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[r("mn",null,"13")])],-1))]),i[6]||(i[6]=o(" 种非必需氨基酸。"))]),i[8]||(i[8]=t('<h4 id="蛋白质的结构" tabindex="-1">蛋白质的结构 <a class="header-anchor" href="#蛋白质的结构" aria-label="Permalink to &quot;蛋白质的结构&quot;">​</a></h4><p><strong>每一种蛋白质分子都有与它所承担功能相适应的独特结构</strong>。</p><h3 id="核酸是遗传信息的携带者" tabindex="-1">核酸是遗传信息的携带者 <a class="header-anchor" href="#核酸是遗传信息的携带者" aria-label="Permalink to &quot;核酸是遗传信息的携带者&quot;">​</a></h3><p><strong>核酸是细胞内携带遗传信息的物质，在生物体的遗传、变异和蛋白质的生物合成中具有及其重要的作用</strong>。</p><p>DNA 功能：<strong>做遗传物质，携带遗传信息；控制生物体的遗传、变异和蛋白质的合成</strong>。</p><p>RNA 功能：做遗传物质；催化；翻译的模板；携带并转运氨基酸；组成核糖体。</p><h3 id="生物大分子以碳链为骨架" tabindex="-1">生物大分子以碳链为骨架 <a class="header-anchor" href="#生物大分子以碳链为骨架" aria-label="Permalink to &quot;生物大分子以碳链为骨架&quot;">​</a></h3><p>生物大分子是由许多单体连接成的多聚体。</p><p>生物大分子以碳链为基本骨架。</p><h2 id="第-3-章-细胞的基本结构" tabindex="-1">第 3 章 细胞的基本结构 <a class="header-anchor" href="#第-3-章-细胞的基本结构" aria-label="Permalink to &quot;第 3 章  细胞的基本结构&quot;">​</a></h2><h3 id="细胞膜的结构和功能" tabindex="-1">细胞膜的结构和功能 <a class="header-anchor" href="#细胞膜的结构和功能" aria-label="Permalink to &quot;细胞膜的结构和功能&quot;">​</a></h3><p>动物和植物细胞的边界都是细胞膜。</p><p>功能：将细胞与外界环境分隔开，保障细胞内部环境的相对稳定；控制物质进出细胞；进行细胞间的信息交流。</p><p>功能越复杂的细胞膜，蛋白质的种类与数量就越多。</p><h3 id="细胞器之间的分工合作" tabindex="-1">细胞器之间的分工合作 <a class="header-anchor" href="#细胞器之间的分工合作" aria-label="Permalink to &quot;细胞器之间的分工合作&quot;">​</a></h3><p>细胞质分为细胞质基质、细胞器和细胞骨架。</p><h4 id="细胞壁" tabindex="-1">细胞壁 <a class="header-anchor" href="#细胞壁" aria-label="Permalink to &quot;细胞壁&quot;">​</a></h4><p>成分：植物细胞（纤维素、果胶）；细菌（肽聚糖，一种糖蛋白）；真菌（几丁质）。</p><p>注：青霉素能够抑制细菌细胞壁合成，从而消灭细菌。</p><h4 id="内质网" tabindex="-1">内质网 <a class="header-anchor" href="#内质网" aria-label="Permalink to &quot;内质网&quot;">​</a></h4><p>光面内质网：脂质的合成场所。</p><p>粗面内质网：参与分泌蛋白的合成、加工和运输。</p><h4 id="高尔基体" tabindex="-1">高尔基体 <a class="header-anchor" href="#高尔基体" aria-label="Permalink to &quot;高尔基体&quot;">​</a></h4><p>对来自内质网的蛋白质进行加工、分类、包装和运输；在植物体细胞中参与细胞壁的形成（纤维素和果胶）；参与溶酶体的形成。</p><h4 id="液泡" tabindex="-1">液泡 <a class="header-anchor" href="#液泡" aria-label="Permalink to &quot;液泡&quot;">​</a></h4><p>含有色素；可以调节细胞内的环境，使细胞保持坚挺。</p><h4 id="溶酶体" tabindex="-1">溶酶体 <a class="header-anchor" href="#溶酶体" aria-label="Permalink to &quot;溶酶体&quot;">​</a></h4><p>植物细胞无溶酶体。</p><h4 id="细胞骨架" tabindex="-1">细胞骨架 <a class="header-anchor" href="#细胞骨架" aria-label="Permalink to &quot;细胞骨架&quot;">​</a></h4><p>细胞骨架是<strong>由蛋白质纤维组成的网架结构</strong>，维持着细胞的形态，锚定并支撑着许多细胞器，与细胞运动、分裂、分化以及物质运输、能量转化、信息传递等生命活动密切相关。</p><h4 id="分泌蛋白的合成和运输" tabindex="-1">分泌蛋白的合成和运输 <a class="header-anchor" href="#分泌蛋白的合成和运输" aria-label="Permalink to &quot;分泌蛋白的合成和运输&quot;">​</a></h4><p>首先，在游离的核糖体中以氨基酸为原料开始多肽链的合成。当合成了一段肽链后，这段肽链会与核糖体一起转移到粗面内质网上继续其合成过程，并且边合成边转移到内质网腔内，再经过加工、折叠，形成具有一定空间结构的蛋白质。内质网膜鼓出形成囊泡，包裹着蛋白质离开内质网，到达高尔基体，与高尔基体膜融合，囊泡膜成为高尔基体膜的一部分。高尔基体还能对蛋白质做进一步的修饰加工，然后由高尔基体膜形成包裹着蛋白质的囊泡。囊泡转运到细胞膜，与细胞膜融合，将蛋白质分泌到细胞外。</p><p>细胞膜、细胞器膜和核膜等结构，共同构成细胞的生物膜系统。</p><h3 id="细胞核的结构和功能" tabindex="-1">细胞核的结构和功能 <a class="header-anchor" href="#细胞核的结构和功能" aria-label="Permalink to &quot;细胞核的结构和功能&quot;">​</a></h3><p>染色质和染色体是同一物质在细胞不同时期的两种存在状态。</p><p><strong>细胞核是遗传信息库，是细胞代谢和遗传的控制中心</strong>。</p><p>细胞既是生物体结构的基本单位，也是生物体代谢和遗传的基本单位。</p>',37))])}]]);export{i as __pageData,d as default};
